// Sadə generic funksiya
function identity<T>(value: T): T {
  return value;
}

let numberResult = identity<number>(42);
let stringResult = identity<string>('Hello');

console.log(numberResult); // 42
console.log(stringResult); // Hello
// let errorResult = identity<number>('test'); // Xəta: 'test' number tipinə uyğun deyil

// Adi funksiya ilə generic funksiyanın müqayisəsi
function returnNumber(value: number): number {
  return value;
}

function returnGeneric<T>(value: T): T {
  return value;
}

let num = returnNumber(10); // Yalnız number tipi
let anyType = returnGeneric<string>('Hello'); // İstənilən tip

console.log(num); // 10
console.log(anyType); // Hello

// Çoxsaylı tip parametrləri
function swap<T, U>(tuple: [T, U]): [U, T] {
  return [tuple[1], tuple[0]];
}

let result = swap<number, string>([1, 'one']);
console.log(result); // ['one', 1]
// let error = swap<number, string>(['test', 42]); // Xəta: 'test' number tipinə uyğun deyil

// Generik tip aliası ilə funksiya
type Pair<K, V> = {
  key: K;
  value: V;
};

function createPair<K, V>(key: K, value: V): Pair<K, V> {
  return { key, value };
}

let numberStringPair = createPair<number, string>(1, 'one');
let stringBooleanPair = createPair<string, boolean>('active', true);

console.log(numberStringPair); // { key: 1, value: 'one' }
console.log(stringBooleanPair); // { key: 'active', value: true }
// let errorPair = createPair<number, string>('test', 'test'); // Xəta: 'test' number tipinə uyğun deyil

// Massivlərlə generic funksiya
function getFirstElement<T>(arr: T[]): T {
  return arr[0];
}

let numbers = [1, 2, 3];
let strings = ['a', 'b', 'c'];

console.log(getFirstElement(numbers)); // 1
console.log(getFirstElement(strings)); // a
// console.log(getFirstElement<number>(strings)); // Xəta: strings number[] tipinə uyğun deyil

// Generik məhdudiyyət nümunəsi
function printLength<T extends { length: number }>(item: T): number {
  return item.length;
}

let str = 'Hello';
let arr = [1, 2, 3];

console.log(printLength(str)); // 5
console.log(printLength(arr)); // 3
// console.log(printLength(42)); // Xəta: 42-də length xüsusiyyəti yoxdur

// Təhlükəsizlik nümunəsi
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}

let person = { name: 'Alice', age: 30 };

console.log(getProperty(person, 'name')); // Alice
console.log(getProperty(person, 'age')); // 30
// console.log(getProperty(person, 'address')); // Xəta: 'address' person obyektində yoxdur

// Səhvə yol açan nümunə
function unsafeIdentity(value: any): any {
  return value;
}

let unsafeResult = unsafeIdentity('Hello');
console.log(unsafeResult); // Hello, lakin tip təhlükəsizliyi yoxdur
unsafeResult = 42; // Keçərlidir, lakin təhlükəsiz deyil

// Düzgün yol
function safeIdentity<T>(value: T): T {
  return value;
}

let safeResult = safeIdentity<string>('Hello');
console.log(safeResult); // Hello
// safeResult = 42; // Xəta: 42 string tipinə uyğun deyil

// Real layihə ssenarisi
function fetchData<T>(data: T): T {
  return data;
}

let userData = fetchData<{ name: string; age: number }>({ name: 'Alice', age: 30 });
let productData = fetchData<{ id: number; name: string }>({ id: 1, name: 'Laptop' });

console.log(userData); // { name: 'Alice', age: 30 }
console.log(productData); // { id: 1, name: 'Laptop' }

