console.log(anyType); // Hello

// Multiple type parameters
function swap<T, U>(tuple: [T, U]): [U, T] {
  return [tuple[1], tuple[0]];
}

let result = swap<number, string>([1, 'one']);
console.log(result); // ['one', 1]
// let error = swap<number, string>(['test', 42]); // Error: 'test' is not assignable to number

// Generic function with type alias
type Pair<K, V> = {
  key: K;
  value: V;
};

function createPair<K, V>(key: K, value: V): Pair<K, V> {
  return { key, value };
}

let numberStringPair = createPair<number, string>(1, 'one');
let stringBooleanPair = createPair<string, boolean>('active', true);

console.log(numberStringPair); // { key: 1, value: 'one' }
console.log(stringBooleanPair); // { key: 'active', value: true }
// let errorPair = createPair<number, string>('test', 'test'); // Error: 'test' is not assignable to number

// Generic function with arrays
function getFirstElement<T>(arr: T[]): T {
  return arr[0];
}

let numbers = [1, 2, 3];
let strings = ['a', 'b', 'c'];

console.log(getFirstElement(numbers)); // 1
console.log(getFirstElement(strings)); // a
// console.log(getFirstElement<number>(strings)); // Error: strings is not assignable to number[]

// Generic constraint example
function printLength<T extends { length: number }>(item: T): number {
  return item.length;
}

let str = 'Hello';
let arr = [1, 2, 3];

console.log(printLength(str)); // 5
console.log(printLength(arr)); // 3
// console.log(printLength(42)); // Error: 42 does not have a length property

// Security example
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}

let person = { name: 'Alice', age: 30 };

console.log(getProperty(person, 'name')); // Alice
console.log(getProperty(person, 'age')); // 30
// console.log(getProperty(person, 'address')); // Error: 'address' does not exist on person

// Error-prone example
function unsafeIdentity(value: any): any {
  return value;
}

let unsafeResult = unsafeIdentity('Hello');
console.log(unsafeResult); // Hello, but no type safety
unsafeResult = 42; // Valid, but unsafe

// Correct approach
function safeIdentity<T>(value: T): T {
  return value;
}

let safeResult = safeIdentity<string>('Hello');
console.log(safeResult); // Hello
// safeResult = 42; // Error: 42 is not assignable to string

// Real-world scenario
function fetchData<T>(data: T): T {
  return data;
}

let userData = fetchData<{ name: string; age: number }>({ name: 'Alice', age: 30 });
let productData = fetchData<{ id: number; name: string }>({ id: 1, name: 'Laptop' });

console.log(userData); // { name: 'Alice', age: 30 }
console.log(productData); // { id: 1, name: 'Laptop' }

